// HelloService.java
@Service
class HelloService {

    private static final Logger logger = LoggerFactory.getLogger(HelloService.class);

    public String getGreeting(String name) {
        logger.debug("Attempting to generate greeting for name: {}", name);
        if (name == null || name.trim().isEmpty()) {
            logger.warn("Received empty or null name for greeting. Defaulting to 'World'.");
            name = "World";
        }
        String greeting = "Hello, " + name + "!";
        logger.info("Successfully generated greeting: '{}'", greeting);
        return greeting;
    }

    public String processData(String input) {
        logger.info("Starting data processing for input: {}", input);
        if (input == null || input.isEmpty()) {
            logger.error("Received null or empty input for data processing.");
            throw new IllegalArgumentException("Input cannot be null or empty.");
        }
        // Simulate some processing
        String processedData = input.toUpperCase() + " - PROCESSED";
        logger.info("Data processing completed successfully for input '{}'. Result: '{}'", input, processedData);
        return processedData;
    }
}

// HelloController.java
@RestController
@RequestMapping("/api")
class HelloController {

    private static final Logger logger = LoggerFactory.getLogger(HelloController.class);

    @Autowired
    private HelloService helloService;

    @GetMapping("/greet")
    public ResponseEntity<String> greet(@RequestParam(value = "name", defaultValue = "Guest") String name) {
        logger.info("Received GET request for /api/greet with name: {}", name);
        try {
            String greeting = helloService.getGreeting(name);
            logger.info("Successfully processed /api/greet request for name '{}'. Responding with: '{}'", name, greeting);
            return ResponseEntity.ok(greeting);
        } catch (Exception e) {
            logger.error("Error processing /api/greet request for name: {}. Error: {}", name, e.getMessage(), e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body("An error occurred while greeting.");
        }
    }

    @GetMapping("/process")
    public ResponseEntity<String> process(@RequestParam(value = "data") String data) {
        logger.info("Received GET request for /api/process with data: {}", data);
        try {
            String processedResult = helloService.processData(data);
            logger.info("Successfully processed /api/process request for data '{}'. Result: '{}'", data, processedResult);
            return ResponseEntity.ok(processedResult);
        } catch (IllegalArgumentException e) {
            logger.warn("Bad request for /api/process: {}", e.getMessage());
            return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(e.getMessage());
        } catch (Exception e) {
            logger.error("Unexpected error processing /api/process request for data: {}. Error: {}", data, e.getMessage(), e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body("An unexpected error occurred during processing.");
        }
    }
}

